+/* ARGSUSED */
+int
+sys_clock_getcpuclockid2(struct thread *td, struct clock_getcpuclockid2_args *uap)
+{
+	clockid_t clk_id;
+	struct proc *p;
+	pid_t pid;
+	lwpid_t tid;
+	int error;
+
+	switch(uap->which) {
+	case CPUCLOCK_WHICH_PID:
+		if (uap->id != 0) {
+			p = pfind(uap->id);
+			if (p == NULL)
+				return (ESRCH);
+			error = p_cansee(td, p);
+			PROC_UNLOCK(p);
+			if (error)
+				return (error);
+			pid = uap->id;
+		} else {
+			pid = td->td_proc->p_pid;
+		}
+		clk_id = MAKE_PROCESS_CPUCLOCK(pid);
+		break;
+	case CPUCLOCK_WHICH_TID:
+		if (uap->id == 0)
+			tid = td->td_tid;
+		else
+			tid = uap->id;
+		clk_id = MAKE_THREAD_CPUCLOCK(tid);
+		break;
+	default:
+		return (EINVAL);
+	}
+	return (copyout(&clk_id, uap->clock_id, sizeof(clockid_t)));
+}
